  ('bookkeeper-moex-01988', 'bookkeeper', 'bookkeeper-moex-101-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '往有商人，貸他半錢，久不得償，即便往債。前有大河，雇他兩錢，然後得渡。到 彼往債，竟不得見。來還渡河，復雇兩錢。為半錢債而失四錢，兼有道路疲勞乏困， 所債甚少，所失極多，果被眾人之所怪笑。（引自《百喻經》）文中商人行徑，最 適合用下列那一成語形容之？', '["捨近求遠", "因小失大", "尺短寸長", "貪多務得"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "35aa60529a7b", "answer_pdf_sha1": "b287ce1418f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
